  // Return an object with name and age properties
  return name + age;
}

solutions.javascript:
// Define a function createPerson that takes name and age as arguments
function createPerson(name: string, age: number) {
  // Return an object with name and age properties
  return {
    name: name,
    age: age
  } as {
    name: string;
    age: number;
  };
}
